import{_ as s,o as a,c as n,a0 as i}from"./chunks/framework.BWpMpcZ2.js";const u=JSON.parse('{"title":"Writing Guide","description":"","frontmatter":{},"headers":[],"relativePath":"writing-guide.md","filePath":"writing-guide.md"}'),t={name:"writing-guide.md"};function l(r,e,o,p,h,d){return a(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="writing-guide" tabindex="-1">Writing Guide <a class="header-anchor" href="#writing-guide" aria-label="Permalink to &quot;Writing Guide&quot;">​</a></h1><h2 id="ai-assist-overview" tabindex="-1">AI Assist Overview <a class="header-anchor" href="#ai-assist-overview" aria-label="Permalink to &quot;AI Assist Overview&quot;">​</a></h2><p>margin uses a <strong>dual-agent architecture</strong> to generate context-aware writing assistance:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  Your Request</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>  ┌─────────────────────┐</span></span>
<span class="line"><span>  │   PLANNER AGENT     │  &lt;-- Reads manifests and reference files</span></span>
<span class="line"><span>  │  (Context Classifier)│      Decides what context is needed</span></span>
<span class="line"><span>  └─────────────────────┘</span></span>
<span class="line"><span>       │ Resolves relevant files</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>  ┌─────────────────────┐</span></span>
<span class="line"><span>  │   WRITER AGENT      │  &lt;-- Receives instruction + context</span></span>
<span class="line"><span>  │  (Prose Generator)  │      Produces the final output</span></span>
<span class="line"><span>  └─────────────────────┘</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>    Your Document</span></span></code></pre></div><ol><li><p><strong>The Planner Agent</strong> looks at your workspace -- it reads manifest files (folder indexes), checks which characters, styles, and lore are relevant to your request, and assembles the right context.</p></li><li><p><strong>The Writer Agent</strong> receives only the instruction, your selected text (if any), and the context prepared by the Planner. It streams the result directly into the editor.</p></li></ol><p>This separation means the AI doesn&#39;t need to read every file in your workspace for every request -- the Planner filters and prioritizes context efficiently.</p><blockquote><p>For a detailed walkthrough of using Edit and Chat modes, see <a href="./ai-assist.html">AI Assist</a>.</p></blockquote><h2 id="workspace-file-structure" tabindex="-1">Workspace File Structure <a class="header-anchor" href="#workspace-file-structure" aria-label="Permalink to &quot;Workspace File Structure&quot;">​</a></h2><p>The code auto-discovers folders and files in your workspace. Any top-level subfolder is treated as a content category. The AI reads files from these folders to ground its responses.</p><h3 id="expected-structure" tabindex="-1">Expected Structure <a class="header-anchor" href="#expected-structure" aria-label="Permalink to &quot;Expected Structure&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>workspace/</span></span>
<span class="line"><span>├── chapters/          Your manuscript content files</span></span>
<span class="line"><span>│   ├── CHAPTERS.md    Manifest: lists all chapter files</span></span>
<span class="line"><span>│   ├── chapter-1.md</span></span>
<span class="line"><span>│   └── chapter-2.md</span></span>
<span class="line"><span>├── characters/        Character profile files</span></span>
<span class="line"><span>│   ├── CHARACTERS.md  Manifest: lists all character files</span></span>
<span class="line"><span>│   ├── elara.md</span></span>
<span class="line"><span>│   └── kaelen.md</span></span>
<span class="line"><span>├── styles/            Tone/style preset files</span></span>
<span class="line"><span>│   ├── STYLES.md      Manifest: lists all style files</span></span>
<span class="line"><span>│   ├── cinematic.md</span></span>
<span class="line"><span>│   └── general.md</span></span>
<span class="line"><span>└── lore/              World-building notes (indexed automatically)</span></span>
<span class="line"><span>    ├── world-map.md</span></span>
<span class="line"><span>    └── factions.md</span></span></code></pre></div><p>Any subfolder you add at the top level is automatically picked up. The name you give the folder becomes the category the Planner uses when deciding what context is relevant.</p><h2 id="manifest-files" tabindex="-1">Manifest Files <a class="header-anchor" href="#manifest-files" aria-label="Permalink to &quot;Manifest Files&quot;">​</a></h2><p><strong>Manifest files</strong> are markdown files with <strong>ALL-CAPS names</strong> that serve as indexes for folders. They tell the Planner what&#39;s available at a glance.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>workspace/characters/</span></span>
<span class="line"><span>├── CHARACTERS.md      &lt;-- Manifest</span></span>
<span class="line"><span>├── elara_vance.md</span></span>
<span class="line"><span>└── kaelen_rhys.md</span></span></code></pre></div><p>Each manifest is a markdown file that lists the files in its folder with a brief description. For example, <code>CHARACTERS.md</code>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> elara_vance.md -- Protagonist, volatile artist</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> kaelen_rhys.md -- Frenemy, sarcastic and grounded</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> lena_hayes.md -- Dr. Lena Hayes, calm scientist</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Manifests are maintained by hand -- when you add or remove files, update the manifest to keep it in sync with the folder contents.</p></div><h3 id="how-the-planner-uses-manifests" tabindex="-1">How the Planner Uses Manifests <a class="header-anchor" href="#how-the-planner-uses-manifests" aria-label="Permalink to &quot;How the Planner Uses Manifests&quot;">​</a></h3><p>When you send a request, the Planner reads all manifest files in your workspace to understand the available context. If your request mentions a character, it checks the characters manifest, finds the relevant profile, and includes it in the context sent to the Writer.</p><p>This means you don&#39;t need to manually specify which files to include -- the Planner handles it automatically based on your content.</p><h2 id="character-profiles" tabindex="-1">Character Profiles <a class="header-anchor" href="#character-profiles" aria-label="Permalink to &quot;Character Profiles&quot;">​</a></h2><p>Create markdown files inside a <code>characters/</code> folder in your workspace. Each file describes a character — the entire file content is sent to the AI when the profile is referenced, so structure it however makes the information clearest for both you and the model:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># Elara Vance</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;"> **Archetype**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: Determined scholar, quiet, cautious.</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;"> **Dialogue**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: Terse, direct, uses academic terms under stress.</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;"> **Physical**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: Silver hair, gray robes, carries a leather-bound logbook.</span></span></code></pre></div><p>When you mention a character name in your request, the Planner automatically finds and includes their profile as context for the Writer.</p><h2 id="style-files" tabindex="-1">Style Files <a class="header-anchor" href="#style-files" aria-label="Permalink to &quot;Style Files&quot;">​</a></h2><p>Writing style guidelines can be stored as markdown files inside a <code>styles/</code> folder in your workspace. Each file is plain markdown with whatever structure works for you:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Writer Guidelines</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Show, don&#39;t tell. Use sensory details.</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Keep descriptions heavy and atmospheric.</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Dialogue should feel natural, not expository.</span></span></code></pre></div><p>Add a <code>STYLES.md</code> manifest in the folder to describe each file:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> cinematic -- Full cinematic scene -- narration sets the atmosphere, dialogue drives the conflict</span></span></code></pre></div><p>Style files are available to the Planner as reference material, just like characters or lore. Pin them in <strong>Settings &gt; Context</strong> if you want them included by default.</p><h2 id="custom-folders" tabindex="-1">Custom Folders <a class="header-anchor" href="#custom-folders" aria-label="Permalink to &quot;Custom Folders&quot;">​</a></h2><p>Any folder you add at the top level of your workspace is automatically indexed by the Planner and included when relevant. The folder name becomes the category the Planner uses when deciding what context to reference.</p><p>Examples: <code>lore/</code> (world-building notes, maps, timelines, magic systems), <code>settings/</code> (locations, factions), or any other category you create.</p><p>Custom folders don&#39;t need manifests -- the Planner auto-indexes any folder contents.</p><h2 id="chapters" tabindex="-1">Chapters <a class="header-anchor" href="#chapters" aria-label="Permalink to &quot;Chapters&quot;">​</a></h2><p>Your chapter or manuscript files go in a folder of your choice (commonly <code>chapters/</code>). The folder name is arbitrary — what matters is the <code>CHAPTERS.md</code> manifest that tells the Planner these are manuscript files.</p>`,37)])])}const k=s(t,[["render",l]]);export{u as __pageData,k as default};
